#!/usr/bin/env python3
"""
Decorpot - Initiation BOM Generator (web app)
Upload an ERP quotation CSV, get the 3-sheet Initiation BOM (Lists/Price/BOM).
Master data + template are built in; team only uploads the CSV.
"""
import os
import io
import tempfile
from flask import Flask, request, send_file, render_template_string, jsonify

import initiation_bom as ib

app = Flask(__name__)

BASE = os.path.dirname(os.path.abspath(__file__))
MASTER = os.path.join(BASE, "master_data.xlsx")
TEMPLATE = os.path.join(BASE, "bom_template.xlsx")

PAGE = r"""
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Initiation BOM Generator · Decorpot</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,500;9..144,600&family=Inter:wght@400;450;500;600&display=swap" rel="stylesheet">
<style>
  :root{
    --bg:#efeae0; --panel:#ffffff; --ink:#1f1d19; --muted:#847d72;
    --line:#eae4d8; --brand:#f07040; --brand-deep:#d85a2a; --navy:#103050; --ok:#2f7d55; --ok-bg:#eef6f0;
  }
  *{box-sizing:border-box}
  html,body{height:100%}
  body{margin:0;font-family:"Inter",system-ui,sans-serif;color:var(--ink);
    -webkit-font-smoothing:antialiased;text-rendering:optimizeLegibility;
    background:
      radial-gradient(1200px 520px at 84% -10%, #fbe7d9 0%, rgba(251,231,217,0) 56%),
      radial-gradient(900px 520px at -5% 112%, #e9ede0 0%, rgba(233,237,224,0) 52%),
      var(--bg);
    display:flex;align-items:center;justify-content:center;padding:32px 24px}
  .wrap{width:100%;max-width:600px}
  .brandrow{display:flex;align-items:center;gap:11px;margin:0 0 20px 2px}
  .brandlogo{height:46px;width:auto;display:block}
  .panel{background:var(--panel);border:1px solid var(--line);border-radius:22px;
    padding:38px 38px 30px;box-shadow:0 24px 60px -30px rgba(60,45,25,.4)}
  .eyebrow{font-size:11.5px;font-weight:600;letter-spacing:.16em;text-transform:uppercase;
    color:var(--brand);margin:0 0 14px}
  h1{font-family:"Fraunces",serif;font-weight:500;font-size:33px;line-height:1.12;
    margin:0 0 12px;letter-spacing:-.015em;color:var(--navy)}
  .lede{color:var(--muted);font-size:15px;line-height:1.6;margin:0 0 28px;max-width:46ch}

  .drop{position:relative;display:block;border:1.5px dashed #d9d0c0;border-radius:16px;
    padding:40px 24px;text-align:center;cursor:pointer;
    transition:border-color .18s ease, background .18s ease;
    background:#fcfbf8}
  .drop:hover{border-color:var(--brand);background:#fdf3ed}
  .drop.drag{border-color:var(--brand);background:#fdefe6}
  .drop.ready{border-style:solid;border-color:#bfe0cc;background:var(--ok-bg)}
  /* fully hide native input - no OS chrome, still clickable via label */
  .drop input[type=file]{position:absolute;width:1px;height:1px;padding:0;margin:-1px;
    overflow:hidden;clip:rect(0 0 0 0);white-space:nowrap;border:0}
  .ic{width:38px;height:38px;margin:0 auto 14px;color:var(--brand);display:block}
  .drop.ready .ic{color:var(--ok)}
  .dtitle{font-weight:600;font-size:15.5px;letter-spacing:-.005em}
  .dhint{color:var(--muted);font-size:12.5px;margin-top:5px;letter-spacing:.01em}
  .fname{margin-top:14px;font-weight:600;color:var(--ok);font-size:14.5px;
    word-break:break-all;letter-spacing:-.005em}
  .swap{margin-top:7px;font-size:12.5px;color:var(--muted);text-decoration:underline;
    text-underline-offset:2px;display:none}

  .btn{margin-top:22px;width:100%;padding:15px;border:0;border-radius:13px;
    font-family:"Inter";font-size:15.5px;font-weight:600;letter-spacing:.005em;cursor:pointer;
    background:var(--brand);color:#fff;transition:background .18s, transform .06s}
  .btn:hover:not(:disabled){background:var(--brand-deep)}
  .btn:active:not(:disabled){transform:translateY(1px)}
  .btn:disabled{background:#e7e0d4;color:#aaa294;cursor:not-allowed}

  .prog{margin-top:22px;display:none}
  .prog.show{display:block}
  .ptrack{height:8px;border-radius:99px;background:#ece5d9;overflow:hidden}
  .pfill{height:100%;width:0;border-radius:99px;background:var(--brand);transition:width .35s ease}
  .pmsg{margin-top:10px;font-size:13px;color:var(--muted);display:flex;justify-content:space-between}
  .pmsg b{font-weight:500;color:var(--ink)}

  .done{margin-top:22px;display:none;align-items:flex-start;gap:11px;
    background:var(--ok-bg);border:1px solid #cfe7d8;border-radius:13px;padding:15px 16px}
  .done.show{display:flex}
  .done .tick{width:22px;height:22px;color:var(--ok);flex:none;margin-top:1px}
  .done .txt{font-size:14px;line-height:1.5}
  .done .txt b{display:block;font-weight:600;color:var(--ink)}
  .done .txt span{color:var(--muted)}

  .err{margin-top:20px;display:none;background:#fdecea;border:1px solid #f3c4bd;
    color:#a3271f;border-radius:12px;padding:13px 15px;font-size:14px;line-height:1.5}
  .err.show{display:block}

  .note{margin-top:24px;padding-top:20px;border-top:1px solid var(--line);
    font-size:12.5px;line-height:1.55;color:var(--muted);display:flex;gap:9px}
  .note .chip{flex:none;width:13px;height:13px;border-radius:4px;margin-top:1px;
    background:#fbe6c9;border:1px solid #eaca92}
  .foot{margin:18px 6px 0;color:var(--muted);font-size:12px;text-align:center;letter-spacing:.01em}
  @media (max-width:520px){ .panel{padding:30px 22px 24px} h1{font-size:27px} }
  @media (prefers-reduced-motion:reduce){ .pfill,.btn{transition:none} }
</style>
</head>
<body>
  <div class="wrap">
    <div class="brandrow">
      <img class="brandlogo" src="data:image/png;base64," alt="Decorpot — Your Trusted Interior Design Partner">
    </div>

    <div class="panel">
      <p class="eyebrow">Initiation BOM</p>
      <h1>Turn a quotation into a ready BOM.</h1>
      <p class="lede">Upload the ERP quotation export. Get back the import-ready Initiation BOM — Lists, Price and BOM sheets, rooms in quotation order.</p>

      <label class="drop" id="drop" for="csv">
        <svg class="ic" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round">
          <path d="M12 15V4M12 4L8 8M12 4l4 4"/><path d="M4 15v3a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2v-3"/>
        </svg>
        <div class="dtitle">Choose CSV file or drag it here</div>
        <div class="dhint">ERP quotation export · .csv</div>
        <div class="fname" id="fname"></div>
        <div class="swap" id="swap">Choose a different file</div>
        <input type="file" id="csv" accept=".csv">
      </label>

      <button class="btn" id="btn" disabled>Generate Initiation BOM</button>

      <div class="prog" id="prog">
        <div class="ptrack"><div class="pfill" id="pfill"></div></div>
        <div class="pmsg"><b id="pmsg">Starting</b><span id="ppct">0%</span></div>
      </div>

      <div class="done" id="done">
        <svg class="tick" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 6L9 17l-5-5"/></svg>
        <div class="txt"><b>Initiation BOM ready</b><span id="donesub">Your download has started.</span></div>
      </div>

      <div class="err" id="err"></div>

      <div class="note">
        <span class="chip"></span>
        <div>Highlighted rows need a quick check against the working drawing — for example False Ceiling area and Wallpaper code.</div>
      </div>
    </div>

    <p class="foot">Master data built in · one CSV at a time · nothing is stored</p>
  </div>

<script>
  const inp=document.getElementById('csv'), drop=document.getElementById('drop'),
        fname=document.getElementById('fname'), swap=document.getElementById('swap'),
        btn=document.getElementById('btn'), prog=document.getElementById('prog'),
        pfill=document.getElementById('pfill'), pmsg=document.getElementById('pmsg'),
        ppct=document.getElementById('ppct'), done=document.getElementById('done'),
        donesub=document.getElementById('donesub'), err=document.getElementById('err');
  let file=null;

  function setFile(f){ if(!f) return; file=f;
    fname.textContent=f.name; swap.style.display='block';
    drop.classList.add('ready'); btn.disabled=false; btn.textContent='Generate Initiation BOM';
    err.classList.remove('show'); done.classList.remove('show');
  }
  inp.addEventListener('change',()=>{ if(inp.files.length) setFile(inp.files[0]); });
  ['dragenter','dragover'].forEach(ev=>drop.addEventListener(ev,e=>{e.preventDefault();drop.classList.add('drag');}));
  ['dragleave','drop'].forEach(ev=>drop.addEventListener(ev,e=>{e.preventDefault();drop.classList.remove('drag');}));
  drop.addEventListener('drop',e=>{ if(e.dataTransfer.files.length){ inp.files=e.dataTransfer.files; setFile(e.dataTransfer.files[0]); }});

  const steps=[[12,'Reading quotation'],[34,'Matching line items'],
               [58,'Applying rules and merging'],[80,'Building Lists · Price · BOM'],[93,'Finalising workbook']];

  btn.addEventListener('click',()=>{
    if(!file) return;
    btn.disabled=true; done.classList.remove('show'); err.classList.remove('show');
    prog.classList.add('show'); pfill.style.width='0%'; ppct.textContent='0%'; pmsg.textContent='Starting';
    let i=0;
    const tick=setInterval(()=>{ if(i<steps.length){ pfill.style.width=steps[i][0]+'%';
      ppct.textContent=steps[i][0]+'%'; pmsg.textContent=steps[i][1]; i++; } },560);

    const fd=new FormData(); fd.append('csv',file);
    fetch('/generate',{method:'POST',body:fd})
      .then(r=>{ if(!r.ok) return r.json().then(j=>{throw new Error(j.error||'Generation failed')});
        return r.blob().then(b=>({b,r})); })
      .then(({b,r})=>{ clearInterval(tick);
        pfill.style.width='100%'; ppct.textContent='100%'; pmsg.textContent='Done';
        const cd=r.headers.get('Content-Disposition')||'';
        const m=cd.match(/filename="?([^"]+)"?/); const name=m?m[1]:'Initiation_BOM.xlsx';
        const url=URL.createObjectURL(b); const a=document.createElement('a');
        a.href=url; a.download=name; document.body.appendChild(a); a.click(); a.remove(); URL.revokeObjectURL(url);
        donesub.textContent=name+' downloaded.';
        setTimeout(()=>{ prog.classList.remove('show'); done.classList.add('show');
          btn.disabled=false; btn.textContent='Generate again'; },450);
      })
      .catch(e=>{ clearInterval(tick); prog.classList.remove('show');
        err.textContent=e.message+'. Please check the CSV and try again.'; err.classList.add('show');
        btn.disabled=false; });
  });
</script>
</body>
</html>
"""

@app.route("/")
def home():
    return render_template_string(PAGE)

@app.route("/generate", methods=["POST"])
def generate():
    f = request.files.get("csv")
    if not f or f.filename == "":
        return jsonify({"error": "Please choose a CSV file"}), 400
    if not f.filename.lower().endswith(".csv"):
        return jsonify({"error": "That isn't a .csv file"}), 400
    with tempfile.TemporaryDirectory() as tmp:
        in_path = os.path.join(tmp, "input.csv")
        out_path = os.path.join(tmp, "Initiation_BOM.xlsx")
        f.save(in_path)
        try:
            cfg = ib.load_config(MASTER)
            results, unmatched = ib.process_csv(in_path, cfg)
            ib.write_output(results, unmatched, out_path, template=TEMPLATE)
            with open(out_path, "rb") as fh:
                data = fh.read()
        except Exception as e:
            return jsonify({"error": f"Could not process this file: {e}"}), 500
    base = os.path.splitext(os.path.basename(f.filename))[0]
    return send_file(io.BytesIO(data),
                     mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                     as_attachment=True, download_name=f"Initiation_BOM_{base}.xlsx")

@app.route("/health")
def health():
    return {"status": "ok"}

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 8000)))
